mapper.select:
select it.issue_type_id, it.initial_status_id, ist.status_name as initial_status_name, it.issue_type_name, it.roadmap_yn, it.description, it.created_at, it.updated_at, it.user_id from issue_type it join issue_status ist on it.initial_status_id = ist.issue_status_id where it.user_id = #{userId} and ist.user_id = #{userId}
and upper(it.issue_type_name) like '%' || upper(#{issueTypeName}) || '%'
and it.initial_status_id = #{initialStatusId}
and it.description is not null
and upper(dbms_lob.substr(it.description, 4000, 1)) like '%' || upper(#{description}) || '%'
order by it.created_at desc, it.issue_type_id desc

select
count(*)
from issue_type
where user_id = #{userId}
and issue_type_name =
#{issueTypeName}

select count(*)
from issue_status
where issue_status_id = #{initialStatusId}
and user_id
= #{userId}

select count(distinct project_id) from project where owner_id = #{userId}
and project_id in
#{projectId}
and 1 = 0

select count(*)
from (
select issue_type_id
from issue
where issue_type_id = #{issueTypeId}

union all

select issue_type_id
from workflow_transition
where
issue_type_id = #{issueTypeId}
)

mapper.delete:
delete from issue_type_project
where issue_type_id in
(
select issue_type_id
from issue_type
where issue_type_id =
#{issueTypeId}
and user_id = #{userId}
)

delete from issue_type_field_setting
where
issue_type_id in (
select issue_type_id
from issue_type
where
issue_type_id = #{issueTypeId}
and user_id = #{userId}
)

delete from issue_type
where issue_type_id =
#{issueTypeId}
and user_id = #{userId}
